$ErrorActionPreference="Stop";$base="C:\Users\hp\Desktop\end-to-go\nono-gate-ci";$sigDir="$base\signals";$out="$base\decision\security-consensus.json";if(!(Test-Path $sigDir)){throw "SIGNALS_DIR_NOT_FOUND"};$sarif=Get-ChildItem -LiteralPath $sigDir -Filter *.sarif -File|Sort-Object Name;if($sarif.Count -eq 0){throw "NO_SARIF_FILES_IN_SIGNALS"};$signals=@();foreach($f in $sarif){$s=Get-Content -LiteralPath $f.FullName -Raw -Encoding UTF8|ConvertFrom-Json;$tool=$null;try{$tool=$s.runs[0].tool.driver.name}catch{$tool=$null};if([string]::IsNullOrWhiteSpace($tool)){$tool=[IO.Path]::GetFileNameWithoutExtension($f.Name)};$levels=@($s.runs|ForEach-Object{$_.results}|ForEach-Object{$_.level.ToString().ToLower()});$err=($levels|Where-Object{$_ -eq "error"}).Count;$crit=($levels|Where-Object{$_ -eq "critical"}).Count;$warn=($levels|Where-Object{$_ -eq "warning"}).Count;$signals+=@{tool=$tool;file=$f.Name;errors=$err;critical=$crit;warnings=$warn;has_blocking=([bool](($err+$crit) -gt 0))}};$blockingTools=@($signals|Where-Object{$_.has_blocking -eq $true}|ForEach-Object{$_.tool}|Sort-Object -Unique);$consensus="PASS";$reason="no blocking findings across tools";if($blockingTools.Count -gt 0){$consensus="BLOCK";$reason=("blocking findings from: "+($blockingTools -join ", "))};$obj=@{engine="nono-gate.consensus.v1";deterministic=$true;consensus=$consensus;rule="block_if_any_tool_has_error_or_critical";signals=($signals|Sort-Object tool,file);blocking_tools=$blockingTools;reason=$reason};$obj|ConvertTo-Json -Depth 8|Set-Content -LiteralPath $out -Encoding UTF8;Write-Output $consensus
